import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F15_關係人交易與利益輸送風險.md"}'),l={name:"審計報告庫/財務審計/4967_十銓/20260428/F15_關係人交易與利益輸送風險.md"};function o(n,a,s,h,c,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f15-關係人交易與利益輸送風險-財務分析專家審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務分析專家審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易（連屬公司、子公司）？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：TR佔比0.13%帳期正常，治理風險低；TJ連虧兩年共$8,796K，恒泰虧$11,160K轉盈$10,995K，跳躍異常需監控。</li><li><strong>風險評級</strong>：低（子公司需持續監控）</li><li><strong>數據時效</strong>：根據截至2025年（民國114年）最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：TR銷貨佔營收0.13%(114年)/0.63%(113年)；DC對母公司銷貨$1,808,946K；TD對母公司銷貨$3,154,686K；子公司淨利：DC $14,454K、TJ $(6,571)K、TD $5,494K、恒泰 $10,995K。</li><li><strong>診斷見解</strong>：外部關係人交易(TR)規模極小且持續縮減，不構成利益輸送風險。DC(香港)與TD(美國)為主要銷貨管道，屬正常營運分工。TJ連續虧損為最大治理隱憂，恒泰劇烈損益翻轉需進一步查證。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="交易規模實測與定價公平性" tabindex="-1">交易規模實測與定價公平性 <a class="header-anchor" href="#交易規模實測與定價公平性" aria-label="Permalink to &quot;交易規模實測與定價公平性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：114年對TR銷貨$26,857K，佔營收0.13%（113年$124,924K佔0.63%），大幅縮減78.5%。TR應收款114年底歸零（113年底$27,386K），帳期月結抵銷。DC/TD/TJ/恒泰為100%持股子公司，銷貨均為合併消除項目。</li><li><strong>深度見解</strong>：TR交易佔比遠低於20%治理紅線且急遽萎縮，公司有意降低對董事長親戚關聯企業依賴。TR曾有65%透由TR轉售予Newegg，屬間接通路非異常交易。租賃$3,381K無低於市價跡象，整體透明度高。</li></ul><h3 id="子公司利潤滲透分析" tabindex="-1">子公司利潤滲透分析 <a class="header-anchor" href="#子公司利潤滲透分析" aria-label="Permalink to &quot;子公司利潤滲透分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DC 114年淨利$14,454K（113年虧損$(5,743)K，轉盈跳躍$20,197K）；TJ淨損$(6,571)K（虧損擴大195%）；TD淨利$5,494K（113年虧$(98)K）；恒泰淨利$10,995K（113年虧$(11,160)K，跳躍$22,155K）。</li><li><strong>深度見解</strong>：DC與恒泰同步劇烈翻轉合計跳躍$42,352K。DC(香港)與恒泰(深圳)存在上下游關係，可能有「利潤轉移」安排。TJ連續虧損且擴大，可能淪為「垃圾桶」角色承接不良資產。</li></ul><h3 id="帳期異常偵測" tabindex="-1">帳期異常偵測 <a class="header-anchor" href="#帳期異常偵測" aria-label="Permalink to &quot;帳期異常偵測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DC月結抵銷、TD/TJ/恒泰月結90天、TR月結抵銷。114年底TR應收款歸零，DC/TD/TJ/恒泰間應收應付於合併時消除。</li><li><strong>深度見解</strong>：90天帳期為國際貿易常規條件。DC「月結抵銷」意味母子公司間無實際資金沉澱，為最有效率的關聯交易安排。TR應收款歸零消除「資金占用」風險。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：TJ連續兩年虧損共計$(8,796)K，虧損幅度逐年擴大195%。在母公司營收與獲利同步成長的環境下，TJ為何持續虧損？是否存在「將高毛利訂單集中於母公司、將低毛利或虧損訂單移至TJ」的利潤分配操作？需查閱TJ單獨財報以驗證此疑慮。</li><li><strong>空頭風險二</strong>：恒泰113年虧$(11,160)K、114年轉盈$10,995K，一年內跳躍$22,155K達198%。深圳公司受中國消費市場與工控需求影響，此劇烈翻轉可能反映「113年集中提列費用、114年輕鬆獲利」的盈餘管理操作，或為合併報表的「利潤調節閥門」。建議追蹤恒泰毛利率是否異常高於母公司（若高出5pp以上即構成「小金庫」疑慮）。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 未調用（年報附註數據充足）</li><li><strong>yfinance</strong>: 未調用</li><li><strong>年報/法說</strong>: OK — 2025_Q4 P.52/66-67/69-70；2024_Q4 P.52-53</li><li><strong>關鍵核對碼</strong>: TR 114年銷貨$26,857K/營收$20,428,449K=0.13%；TJ 114年淨損$(6,571)K vs 113年$(2,225)K；恒泰 114年淨利$10,995K vs 113年淨損$(11,160)K</li></ul>',19)])])}const T=t(l,[["render",o]]);export{u as __pageData,T as default};
